def normalize_config(cfg):
    cfg = dict(cfg or {})
    cfg.setdefault("services", [])
    cfg.setdefault("upstreams", [])
    cfg.setdefault("targets", [])
    return cfg


def ensure_service_route_links(cfg):
    service_names = {s.get("name") for s in cfg.get("services", []) if s.get("name")}
    for s in cfg.get("services", []):
        routes = s.get("routes", [])
        for r in routes:
            if "service" not in r:
                r["service"] = {"name": s["name"]}
        for r in routes:
            cfg.setdefault("routes", []).append(r)
    if "routes" in cfg:
        for r in cfg["routes"]:
            svc = r.get("service", {})
            svc_name = svc.get("name")
            if svc_name and svc_name not in service_names:
                pass
    return cfg


def apply_config(kong, cfg):
    cfg = normalize_config(cfg)
    cfg = ensure_service_route_links(cfg)

    results = {"services": [], "routes": [], "upstreams": [], "targets": []}

    for upstream in cfg.get("upstreams", []):
        created = kong.create_upstream(upstream)
        results["upstreams"].append(created)

    for t in cfg.get("targets", []):
        up = t.get("upstream")
        if not up:
            raise ValueError("Each target entry requires 'upstream' (name or id) and 'target' payload fields.")
        target_payload = {k: v for k, v in t.items() if k != "upstream"}
        created = kong.create_target(up, target_payload)
        results["targets"].append(created)

    for service in cfg.get("services", []):
        svc_payload = {k: v for k, v in service.items() if k != "routes"}
        created = kong.create_service(svc_payload)
        results["services"].append(created)

    routes = cfg.get("routes", [])
    for route in routes:
        created = kong.create_route(route)
        results["routes"].append(created)

    return results


def load_config(path):
    with open(path, "r", encoding="utf-8") as f:
        raw = f.read().strip()
    if not raw:
        return {}
    return json.loads(raw)


